"use client";

import React, { useEffect, useRef, useState } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { ArrowRight, Zap, TrendingUp, Shield, Globe } from "lucide-react";

// ─── Types ─────────────────────────────────────────────────────────

interface HeroProps {
  variant?: "network" | "edtech";
}

// ─── Data ──────────────────────────────────────────────────────────

const NETWORK_CONTENT = {
  eyebrow: "CISCO ACQUISITION",
  headline: "Performance Intelligence",
  headlineAccent: "Redefined",
  subheadline:
    "Accedian delivers real-time network and application performance analytics that empower enterprises to see, understand, and act — before users even notice a problem.",
  ctaPrimary: "Explore Platform",
  ctaSecondary: "Watch Demo",
  stats: [
    { value: "99.99%", label: "Uptime SLA" },
    { value: "<1ms", label: "Detection Latency" },
    { value: "500+", label: "Enterprise Clients" },
  ],
  features: [
    { icon: Zap, label: "Real-time Observability" },
    { icon: Shield, label: "Zero-trust Security" },
    { icon: Globe, label: "Global Edge Network" },
  ],
  gradientFrom: "from-violet-600",
  gradientTo: "to-fuchsia-500",
  accentColor: "text-fuchsia-400",
  bgGlow: "bg-fuchsia-500/10",
};

const EDTECH_CONTENT = {
  eyebrow: "INDIA'S TOP ED-TECH PLATFORM",
  headline: "Upskill. Transform.",
  headlineAccent: "Lead.",
  subheadline:
    "Accredian empowers working professionals with industry-aligned programs in Data Science, AI, Product Management, and Digital Transformation — built by IIT/IIM alumni.",
  ctaPrimary: "Browse Programs",
  ctaSecondary: "Talk to Advisor",
  stats: [
    { value: "50,000+", label: "Learners Placed" },
    { value: "₹24L", label: "Avg. Salary Hike" },
    { value: "300+", label: "Hiring Partners" },
  ],
  features: [
    { icon: TrendingUp, label: "Career Acceleration" },
    { icon: Zap, label: "Live Mentorship" },
    { icon: Shield, label: "Job Guarantee" },
  ],
  gradientFrom: "from-cyan-500",
  gradientTo: "to-amber-400",
  accentColor: "text-amber-400",
  bgGlow: "bg-amber-500/10",
};

// ─── Sub-Components ────────────────────────────────────────────────

const AnimatedCounter = ({ target, suffix = "" }: { target: string; suffix?: string }) => {
  return (
    <motion.span
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.8, ease: "easeOut" }}
      className="tabular-nums"
    >
      {target}{suffix}
    </motion.span>
  );
};

const FloatingOrb = ({
  className,
  delay = 0,
}: {
  className: string;
  delay?: number;
}) => {
  return (
    <motion.div
      className={`absolute rounded-full blur-3xl opacity-30 pointer-events-none ${className}`}
      animate={{
        y: [0, -40, 0],
        x: [0, 20, -20, 0],
        scale: [1, 1.1, 0.95, 1],
      }}
      transition={{
        duration: 12,
        repeat: Infinity,
        delay,
        ease: "easeInOut",
      }}
    />
  );
};

// ─── Main Component ────────────────────────────────────────────────

export default function HeroSection({ variant = "network" }: HeroProps) {
  const content = variant === "network" ? NETWORK_CONTENT : EDTECH_CONTENT;
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end start"],
  });

  const y = useTransform(scrollYProgress, [0, 1], [0, 150]);
  const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0]);

  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({
        x: (e.clientX / window.innerWidth - 0.5) * 20,
        y: (e.clientY / window.innerHeight - 0.5) * 20,
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <section
      ref={containerRef}
      className="relative min-h-screen w-full overflow-hidden bg-slate-950 text-white"
    >
      {/* ─── Background Effects ───────────────────────────────────── */}
      <div className="absolute inset-0 overflow-hidden">
        <FloatingOrb
          className={`w-[600px] h-[600px] -top-40 -right-40 ${content.bgGlow}`}
          delay={0}
        />
        <FloatingOrb
          className={`w-[500px] h-[500px] top-1/2 -left-40 ${content.bgGlow}`}
          delay={3}
        />
        <FloatingOrb
          className={`w-[400px] h-[400px] bottom-0 right-1/4 ${content.bgGlow}`}
          delay={6}
        />

        {/* Grid Pattern */}
        <div
          className="absolute inset-0 opacity-[0.03]"
          style={{
            backgroundImage: `linear-gradient(rgba(255,255,255,0.1) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.1) 1px, transparent 1px)`,
            backgroundSize: "60px 60px",
          }}
        />

        {/* Radial vignette */}
        <div className="absolute inset-0 bg-radial-gradient pointer-events-none" />
      </div>

      {/* ─── Content ──────────────────────────────────────────────── */}
      <motion.div
        style={{ y, opacity }}
        className="relative z-10 flex flex-col items-center justify-center min-h-screen px-6 sm:px-8 lg:px-12 py-24"
      >
        <div className="max-w-7xl mx-auto w-full">
          <div className="grid lg:grid-cols-2 gap-16 lg:gap-24 items-center">
            {/* Left Column — Text */}
            <div className="flex flex-col items-start space-y-8">
              {/* Eyebrow */}
              <motion.div
                initial={{ opacity: 0, x: -30 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.6, delay: 0.1 }}
                className="flex items-center gap-3"
              >
                <span className={`h-px w-8 ${content.gradientFrom.replace("from-", "bg-")}`} />
                <span className="text-xs sm:text-sm font-semibold tracking-[0.2em] uppercase text-slate-400">
                  {content.eyebrow}
                </span>
              </motion.div>

              {/* Headline */}
              <motion.h1
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.2, ease: [0.22, 1, 0.36, 1] }}
                className="text-5xl sm:text-6xl lg:text-7xl xl:text-8xl font-bold leading-[0.95] tracking-tight"
                style={{
                  transform: `translate(${mousePos.x}px, ${mousePos.y}px)`,
                  transition: "transform 0.3s ease-out",
                }}
              >
                {content.headline}
                <br />
                <span
                  className={`bg-gradient-to-r ${content.gradientFrom} ${content.gradientTo} bg-clip-text text-transparent`}
                >
                  {content.headlineAccent}
                </span>
              </motion.h1>

              {/* Subheadline */}
              <motion.p
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.4 }}
                className="text-lg sm:text-xl text-slate-400 max-w-xl leading-relaxed"
              >
                {content.subheadline}
              </motion.p>

              {/* CTAs */}
              <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.5 }}
                className="flex flex-wrap gap-4 pt-2"
              >
                <button
                  className={`group relative px-8 py-4 rounded-full font-semibold text-sm tracking-wide overflow-hidden bg-gradient-to-r ${content.gradientFrom} ${content.gradientTo} text-white shadow-lg shadow-${content.gradientFrom.split("-")[1]}-500/25 hover:shadow-xl hover:shadow-${content.gradientFrom.split("-")[1]}-500/40 transition-all duration-300`}
                >
                  <span className="relative z-10 flex items-center gap-2">
                    {content.ctaPrimary}
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                  </span>
                  <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
                </button>

                <button className="px-8 py-4 rounded-full font-semibold text-sm tracking-wide border border-slate-700 text-slate-300 hover:border-slate-500 hover:text-white transition-all duration-300">
                  {content.ctaSecondary}
                </button>
              </motion.div>

              {/* Features */}
              <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.6 }}
                className="flex flex-wrap gap-6 pt-6"
              >
                {content.features.map((feature, i) => (
                  <div
                    key={i}
                    className="flex items-center gap-2 text-sm text-slate-400"
                  >
                    <feature.icon className={`w-4 h-4 ${content.accentColor}`} />
                    <span>{feature.label}</span>
                  </div>
                ))}
              </motion.div>
            </div>

            {/* Right Column — Stats Card */}
            <motion.div
              initial={{ opacity: 0, scale: 0.9, rotateY: -10 }}
              animate={{ opacity: 1, scale: 1, rotateY: 0 }}
              transition={{ duration: 1, delay: 0.4, ease: [0.22, 1, 0.36, 1] }}
              className="relative"
              style={{
                transform: `perspective(1000px) rotateY(${mousePos.x * 0.3}deg) rotateX(${-mousePos.y * 0.3}deg)`,
                transition: "transform 0.3s ease-out",
              }}
            >
              <div className="relative bg-slate-900/50 backdrop-blur-xl border border-slate-800 rounded-3xl p-8 sm:p-10 overflow-hidden">
                {/* Card glow */}
                <div
                  className={`absolute -top-20 -right-20 w-40 h-40 rounded-full blur-3xl ${content.bgGlow}`}
                />

                <div className="relative z-10">
                  <h3 className="text-sm font-semibold tracking-[0.15em] uppercase text-slate-500 mb-8">
                    Impact at a Glance
                  </h3>

                  <div className="space-y-8">
                    {content.stats.map((stat, i) => (
                      <motion.div
                        key={i}
                        initial={{ opacity: 0, x: 30 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6, delay: 0.6 + i * 0.15 }}
                        className="group"
                      >
                        <div className="flex items-baseline gap-3 mb-1">
                          <span
                            className={`text-4xl sm:text-5xl font-bold bg-gradient-to-r ${content.gradientFrom} ${content.gradientTo} bg-clip-text text-transparent`}
                          >
                            <AnimatedCounter target={stat.value} />
                          </span>
                        </div>
                        <div className="h-px w-full bg-slate-800 group-hover:w-3/4 transition-all duration-500">
                          <div
                            className={`h-full w-0 group-hover:w-full bg-gradient-to-r ${content.gradientFrom} ${content.gradientTo} transition-all duration-700`}
                          />
                        </div>
                        <p className="text-sm text-slate-500 mt-2">{stat.label}</p>
                      </motion.div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Decorative ring */}
              <div className="absolute -inset-1 rounded-3xl border border-slate-800/50 -z-10" />
              <div className="absolute -inset-2 rounded-3xl border border-slate-800/30 -z-20" />
            </motion.div>
          </div>
        </div>
      </motion.div>

      {/* ─── Bottom Gradient Fade ──────────────────────────────────── */}
      <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-slate-950 to-transparent pointer-events-none" />
    </section>
  );
}